mapper.select:
SELECT id, supplier_name, month_from, month_to, note, is_deleted, create_name, create_id, create_date, update_name, update_id, update_date FROM sp_meeting_note WHERE is_deleted = 0
AND supplier_name LIKE CONCAT('%', #{supplierName}, '%')
AND month_from >= #{monthFrom}
AND month_to <= #{monthTo}
ORDER BY create_date DESC

mapper.update:
UPDATE sp_meeting_note
supplier_name = #{supplierName}, month_from = #{monthFrom}, month_to = #{monthTo}, note = #{note}, update_name = #{updateName}, update_id = #{updateId},
WHERE id = #{id}
